#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        long long sum = 0, ans = 0;
        for (int i = 1; i <= N; ++i) {
            int a;
            scanf("%d", &a);
            sum += a;
            if (sum == i) ans++;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

