#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.buffer.read().split()
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))
        total = 0
        ans = 0
        for i in range(1, n + 1):
            a = int(next(it))
            total += a
            if total == i:
                ans += 1
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

